    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
